previewCss:
.darma-loader-darma-custom-113 {
  height: 45px;
  --c:no-repeat linear-gradient(var(--loader-color, #514b82) 0 0);
  background: 
    var(--c) left,
    var(--c) center,
    var(--c) right;
  background-size: 16px 100%;
  animation: 
    darma-loader-darma-custom-113-l33-1 1.5s infinite,
    darma-loader-darma-custom-113-l33-2 1.5s infinite;
}
@keyframes darma-loader-darma-custom-113-l33-1 {
  0%,100% {width:45px}
  35%,65% {width:65px}
}
@keyframes darma-loader-darma-custom-113-l33-2 {
  0%,40%  {transform: rotate(0) }
  60%,100%{transform: rotate(90deg) }
}

